import React, { useState, useEffect, useCallback, useMemo } from 'react';
import Select from 'react-select';
import './PurchaseFunc.css';
import AddMaterial from './AddMaterial.js';
import AddVendor from './AddVendor.js';

const AddPurchase = ({ handleAdd, locations, materials, setMaterials, vendors, setVendors, apiBaseUrl, order }) => {
  const [showAddMaterialForm, setShowAddMaterialForm] = useState(false);
  const [showAddVendorForm, setShowAddVendorForm] = useState(false);

  const initialPurchaseState = useMemo(
    () =>
      order
        ? {
            location: order.location_id || '',
            materialid: order.material_id || '',
            materialname: materials.find((m) => order.material_id === m.matid)?.name || '',
            quantity: order.quantity || '',
            price: order.unitprice || '',
            vendor: order.vendor_id || '',
            vendorname: order.vendorname || '',
            width: order.width || null,
            lotnumber: order.lotnumber || '',
            comments: order.comments || '',
            invdate: order.invdate || '',
            verification: order.verification || '',
          }
        : {
            location: '',
            materialid: '',
            materialname: '',
            quantity: '',
            price: '',
            vendor: '',
            vendorname: '',
            width: null,
            lotnumber: '',
            comments: '',
            invdate: '',
            verification: '',
          },
    [order, materials]
  );

  const [newPurchase, setNewPurchase] = useState(initialPurchaseState);
  const [showExtras, setShowExtras] = useState(false);

  const fetchWithAuth = useCallback(
    async (url, options = {}) => {
      const authToken = sessionStorage.getItem('authToken');
      return fetch(url, {
        ...options,
        headers: {
          ...options.headers,
          Authorization: `Bearer ${authToken}`,
        },
      });
    },
    []
  );

  useEffect(() => {
    const fetchMaterialData = async () => {
      if (!newPurchase.materialid) {
        setShowExtras(false);
        setNewPurchase((prev) => ({
          ...prev,
          price: '',
          vendor: '',
          vendorname: '',
          materialname: '',
        }));
        return;
      }

      try {
        const [responseChanges, responseList] = await Promise.all([
          fetchWithAuth(`${apiBaseUrl}/materialchangesAPI/${newPurchase.materialid}`),
          fetchWithAuth(`${apiBaseUrl}/materiallist/${newPurchase.materialid}`),
        ]);

        const [dataChanges, dataList] = await Promise.all([responseChanges.json(), responseList.json()]);

        setShowExtras(dataList?.extras === 1);

        setNewPurchase((prev) => ({
          ...prev,
          price: dataChanges?.price || '',
          vendor: dataChanges?.vendor || '',
          vendorname: vendors.find((vendor) => vendor.vendorid === dataChanges?.vendor)?.name || '',
          materialname: dataList?.name || '',
        }));
      } catch (error) {
        console.error('Error fetching material data:', error);
      }
    };

    fetchMaterialData();
  }, [newPurchase.materialid, vendors, apiBaseUrl, fetchWithAuth]);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setNewPurchase((prev) => ({
      ...prev,
      [name]: value,
    }));
  };

  const handleMaterialChange = (selectedOption, type) => {
    const material = type === 'id'
      ? materials.find((m) => m.matid === selectedOption.value)
      : materials.find((m) => m.name === selectedOption.label);

    setNewPurchase((prev) => ({
      ...prev,
      materialid: material?.matid || '',
      materialname: material?.name || '',
    }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      const responseChanges = await fetchWithAuth(`${apiBaseUrl}/materialchangesAPI/${newPurchase.materialid}`);
      const dataChanges = await responseChanges.json();

      if (dataChanges?.price !== newPurchase.price || dataChanges?.vendor !== newPurchase.vendor) {
        await fetchWithAuth(`${apiBaseUrl}/materialchangesAPI/`, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            material_id: newPurchase.materialid,
            price: newPurchase.price,
            vendor: newPurchase.vendor,
          }),
        });
      }

      handleAdd(newPurchase);
      setNewPurchase(initialPurchaseState);
    } catch (error) {
      console.error('Error handling the form submission:', error);
    }
  };

  const materialOptions = useMemo(
    () => materials.map((material) => ({ value: material.matid, label: material.matid })),
    [materials]
  );

  const vendorOptions = useMemo(
    () =>
      vendors.map((vendor) => ({
        value: vendor.vendorid,
        label: vendor.name,
      })),
    [vendors]
  );

  return (
    <div className="container">
      <h2 className="heading">Add Purchase</h2>
      <form onSubmit={handleSubmit} className="form">
        <div className="form-row">
          <div className="form-group">
            <label>Location:</label>
            <select name="location" value={newPurchase.location} onChange={handleChange} required>
              <option value="">Select a location</option>
              {locations.map((location) => (
                <option key={location.id} value={location.id}>
                  {location.locationname}
                </option>
              ))}
            </select>
          </div>

          <div className="form-group">
            <label>Material ID:</label>
            <Select
              classNamePrefix="select-field"
              name="materialid"
              value={newPurchase.materialid ? { value: newPurchase.materialid, label: newPurchase.materialid } : null}
              options={materialOptions}
              onChange={(option) => handleMaterialChange(option, 'id')}
              placeholder="Select a material ID"
              required
            />
          </div>

          <div className="form-group">
            <label>Material Name:</label>
            <Select
              classNamePrefix="select-field"
              name="materialname"
              value={newPurchase.materialname ? { value: newPurchase.materialname, label: newPurchase.materialname } : null}
              options={materials.map((material) => ({
                value: material.name,
                label: material.name,
              }))}
              onChange={(option) => handleMaterialChange(option, 'name')}
              placeholder="Select a material name"
              required
            />
          </div>

          {showExtras && (
            <>
              <div className="form-group">
                <label>Width:</label>
                <input type="number" name="width" value={newPurchase.width || ''} onChange={handleChange} required />
              </div>
              <div className="form-group">
                <label>LOT#:</label>
                <input type="text" name="lotnumber" value={newPurchase.lotnumber || ''} onChange={handleChange} required />
              </div>
            </>
          )}

          <div className="form-group">
            <label>Quantity:</label>
            <input type="text" name="quantity" value={newPurchase.quantity} onChange={handleChange} required />
          </div>

          <div className="form-group">
            <label>Price:</label>
            <input type="text" name="price" value={newPurchase.price || ''} onChange={handleChange} required />
          </div>

          <div className="form-group">
            <label>Vendor:</label>
            <Select
              name="vendor"
              value={newPurchase.vendor ? { value: newPurchase.vendor, label: newPurchase.vendorname } : null}
              options={vendorOptions}
              onChange={(option) => handleChange({ target: { name: 'vendor', value: option.value } })}
              placeholder="Select a vendor"
              required
            />
          </div>

          <div className="form-group">
            <label>Comments:</label>
            <textarea name="comments" value={newPurchase.comments} onChange={handleChange} />
          </div>

          <div className="form-group">
            <label>Invoice Date:</label>
            <input type="date" name="invdate" value={newPurchase.invdate} onChange={handleChange} />
          </div>

          <button type="submit" className="add_btn">Add Purchase</button>
        </div>
      </form>

      {showAddMaterialForm && (
        <div className="overlay">
          <div className="popup">
            <span className="close-popup" onClick={() => setShowAddMaterialForm(false)}>&times;</span>
            <AddMaterial handleAdd={setMaterials} />
          </div>
        </div>
      )}

      {showAddVendorForm && (
        <div className="overlay">
          <div className="popup">
            <span className="close-popup" onClick={() => setShowAddVendorForm(false)}>&times;</span>
            <AddVendor handleAddVendor={setVendors} />
          </div>
        </div>
      )}
    </div>
  );
};

export default AddPurchase;
